previewCss:
.darma-loader-darma-custom-748 {
  color: var(--loader-color, #f97316);
  --loader-secondary-color: var(--loader-secondary-color, #fdba74);
  --loader-bg: var(--loader-bg, #ffffff);
width: 50px;
height: 28px;
--_g: no-repeat radial-gradient(farthest-side,currentColor 94%,#0000);
background:
var(--_g) 50% 0,
var(--_g) 100% 0;
background-size: 12px 12px;
position: relative;
animation: darma-loader-darma-custom-748-l23-0 1.5s linear infinite;
}
.darma-loader-darma-custom-748:before {
content: "";
position: absolute;
height: 12px;
aspect-ratio: 1;
border-radius: 50%;
background: currentColor;
left:0;
top:0;
animation:
darma-loader-darma-custom-748-l23-1 1.5s linear infinite,
darma-loader-darma-custom-748-l23-2 0.5s cubic-bezier(.45, 0, .55, 1) infinite;
}
@keyframes darma-loader-darma-custom-748-l23-0 {
0%,31% {background-position: 50% 0 ,100% 0}
33% {background-position: 50% 100%,100% 0}
43%,64% {background-position: 50% 0 ,100% 0}
66% {background-position: 50% 0 ,100% 100%}
79% {background-position: 50% 0 ,100% 0}
100% {transform:translateX(calc(-100%/3))}
}
@keyframes darma-loader-darma-custom-748-l23-1 {
100% {left:calc(100% + 7px)}
}
@keyframes darma-loader-darma-custom-748-l23-2 {
100% {top:-0.1px}
}

